import React from 'react';

const COLORS = ['#ff4757','#ff6b35','#ffa502','#3d7fff','#2ed573'];
const LABELS = ['Very Weak','Weak','Fair','Strong','Very Strong'];

export default function OverallScore({ result }) {
  const score = result.overallScore;
  const color = COLORS[score];
  const label = LABELS[score];
  const pct = ((score + 1) / 5) * 100;
  const radius = 40;
  const circumference = 2 * Math.PI * radius;
  const dash = (pct / 100) * circumference;

  return (
    <div className="score-card" style={{ '--score-color': color }}>
      <div className="score-ring">
        <svg width="100" height="100" viewBox="0 0 100 100">
          <circle cx="50" cy="50" r={radius} fill="none" stroke="var(--bg-3)" strokeWidth="6" />
          <circle
            cx="50" cy="50" r={radius}
            fill="none"
            stroke={color}
            strokeWidth="6"
            strokeDasharray={`${dash} ${circumference}`}
            strokeLinecap="round"
            style={{
              transition: 'stroke-dasharray 0.7s cubic-bezier(0.4,0,0.2,1), stroke 0.4s ease',
              filter: `drop-shadow(0 0 6px ${color}60)`
            }}
          />
        </svg>
        <div className="score-ring-text">
          <span className="score-number" style={{ color }}>{score}</span>
          <span className="score-of">/ 4</span>
        </div>
      </div>
      <div className="score-strength-label" style={{ color }}>{label}</div>
      <div className="score-entropy-line">
        Entropy: <strong style={{ color: 'var(--cyan)' }}>{result.entropy.bits} bits</strong>
        &nbsp;·&nbsp;
        Charset: <strong style={{ color: 'var(--cyan)' }}>{result.entropy.charsetSize}</strong>
        &nbsp;·&nbsp;
        {result.entropy.combinations.toExponential(2)} combos
      </div>
    </div>
  );
}
